var gameState = "start";

var hewbert = createSprite(100, 300, 30, 40);
hewbert.setAnimation("hewbert");
hewbert.scale = 0.3;
hewbert.velocityY = 0;
hewbert.health = 90;
hewbert.blocking = false;

var boss = createSprite(320, 300, 60, 80);
boss.setAnimation("axel");
boss.scale = 0.2;
boss.health = 400;
boss.velocityY = 0;

var bossFireballs = new Group();
var playerFireballs = new Group();
var explosionGroup = new Group();
var confettiGroup = new Group();

var gravity = 0.8;
var jumpForce = -12;
var groundY = 340;

function drawStartScreen() {
background("black");
fill("white");
textSize(20);
textAlign(CENTER);
text("BOSS ARENA", 200, 80);
textSize(14);
text("W = Jump", 200, 140);
text("A/D = Move", 200, 160);
text("L = Shoot", 200, 180);
text("Press SPACE to Begin", 200, 260);
}

function createExplosion(x, y) {
for (var i = 0; i < 8; i++) {
var p = createSprite(x, y, 8, 8);
p.shapeColor = random(["orange","yellow","red"]);
p.velocityX = random(-4,4);
p.velocityY = random(-4,4);
p.life = 15;
explosionGroup.add(p);
}
}

function playerControls() {

if (keyDown("a")) {
hewbert.x -= 5;
}

if (keyDown("d")) {
hewbert.x += 5;
}

var hewbertHeight = hewbert.height * hewbert.scale;

if (keyWentDown("w") && hewbert.y >= groundY - hewbertHeight/2 - 1) {
hewbert.velocityY = jumpForce;
}

if (keyWentDown("l")) {
var fireball = createSprite(hewbert.x + 20, hewbert.y, 15, 15);
fireball.shapeColor = "orange";
fireball.velocityX = 8;
fireball.life = 60;
playerFireballs.add(fireball);
}
}

function bossAI() {

var bossHeight = boss.height * boss.scale;

if (random(1,100) < 2 && boss.y >= groundY - bossHeight/2 - 1) {
boss.velocityY = jumpForce;
}

if (frameCount % 25 === 0) {
var fireball = createSprite(boss.x - 30, boss.y, 20, 20);
fireball.shapeColor = "yellow";
fireball.velocityX = -7;
fireball.life = 120;
bossFireballs.add(fireball);
}
}

function applyGravity(sprite) {

sprite.velocityY += gravity;
sprite.y += sprite.velocityY;

var spriteHeight = sprite.height * sprite.scale;

if (sprite.y > groundY - spriteHeight/2) {
sprite.y = groundY - spriteHeight/2;
sprite.velocityY = 0;
}
}

function drawHealthBars() {
fill("green");
rect(20, 20, hewbert.health * 2, 15);

fill("red");
rect(200, 20, boss.health * 0.5, 15);
}

function createConfetti() {
for (var i = 0; i < 60; i++) {
var c = createSprite(random(0,400), random(-400,0), 5, 5);
c.shapeColor = random(["red","blue","yellow","green","purple"]);
c.velocityY = random(2,6);
c.life = 120;
confettiGroup.add(c);
}
}

function draw() {

if (gameState === "start") {
drawStartScreen();

if (keyWentDown("space")) {
  gameState = "play";
}

}

if (gameState === "play") {

background("lightblue");

fill("brown");
rect(0, groundY, 400, 60);

playerControls();
bossAI();

applyGravity(hewbert);
applyGravity(boss);

if (hewbert.x < 0) {
  hewbert.x = 0;
}

if (hewbert.x > 400) {
  hewbert.x = 400;
}

for (var i = 0; i < bossFireballs.length; i++) {

if (bossFireballs[i].isTouching(hewbert)) {

createExplosion(hewbert.x, hewbert.y);

if (!hewbert.blocking) {
      hewbert.health -= 10;
    }

bossFireballs[i].remove();
  }
}

for (var j = 0; j < playerFireballs.length; j++) {

if (playerFireballs[j].isTouching(boss)) {

createExplosion(boss.x, boss.y);
boss.health -= 10;

playerFireballs[j].remove();
  }
}

drawHealthBars();
drawSprites();

if (hewbert.health <= 0) {

background("black");

fill("red");
textSize(30);
textAlign(CENTER);
text("YOU LOST", 200, 200);

noLoop();
}

if (boss.health <= 0) {

createExplosion(boss.x, boss.y);
boss.remove();

gameState = "win";

createConfetti();
}

}

if (gameState === "win") {

background("black");

drawSprites();

fill("white");
textSize(28);
textAlign(CENTER);
text("YOU DEFEATED AXEL!", 200, 200);

}
}
